var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"으헉…!","JPN":"ぐはっ……！","ENG":"Kuh...!","TWN":"呃呃…！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"제길… 보물을 코앞에 두고 저런 꼬맹이가 훼방을 놓다니.","JPN":"くそ……宝を前にして、あんなガキに邪魔されるなんて。","ENG":"Darn... Can't believe I have to give up on that treasure because a kid got in the way.","TWN":"該死的…寶藏眼看就要到手了，這個小丫頭搗什麼亂。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"당신들. 눈앞의 보물엔 그렇게 목숨을 걸면서, 정작 바다에 나갈 용기는 없는 거야?","JPN":"あなたたち。目の前の宝にはそうやって命を懸けるくせに、海に出る勇気はないの？","ENG":"Hey. You risk your lives for treasure right in front of your eyes, but why don't you have the balls to go out to sea?","TWN":"你們願意為眼前的寶藏冒生命危險，卻沒有勇氣出海？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"내가 미쳤어? 크라켄이 버젓이 활개치고 있는데 바다로 나가라고?","JPN":"ふざけてんのか。クラーケンが暴れまわってるのに、海に出ろって？","ENG":"Are you crazy? Who in their right mind would go out to sea when Kraken is rampaging all over?","TWN":"我又不是瘋子，克拉肯如此活躍的時候要我出海？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"마, 맞아! 이런 시기에 바다로 나가는 건 죽겠다는 소리잖아!","JPN":"そ、そうだ！　こんな時に海に出るのは死ぬってことだろ！","ENG":"Y-yeah! Going out to sea at a time like this means you're suicidal!","TWN":"就…就是說！每年這個時候出海就是找死！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"목숨이라면 토큰 하나에도 항상 걸어왔잖아?","JPN":"命なら、いつもトークンにもかけてきただろう？","ENG":"You've always risked your lives for measly tokens, though.","TWN":"你們還不是常常為了一個代幣而冒著生命危險？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"목숨이야 언제나처럼 하나만 걸면 되지만, 배에 보물을 한가득 실을 기회는 다신 없을 거야.","JPN":"命なんていつものように一つだけかければいいが、船に宝をいっぱい乗せるチャンスは二度とない。","ENG":"But this time, you'd be risking your life for a chance to fill your ship with treasure. It's a once-in-a-lifetime opportunity.","TWN":"像往常一樣堵上性命，就能收穫滿滿的寶藏。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"운이 좋다면, 에이버리의 함선을 찾아내고 평생 떵떵거리며 살게 될지도 모르지.","JPN":"運が良ければ、エイバリーの艦船を見つけ出し、一生贅沢に暮らせるかもしれない。","ENG":"If you're lucky, you might find Avery's ship and be set for life.","TWN":"運氣好的話，你還能找到艾維利的艦船，風風光光地過一輩子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"쳇, 내가 같은 해적 속내도 모를 줄 알아?","JPN":"ちっ、同じ海賊の本心なんざお見通しだ。","ENG":"Tch. I'm a pirate too, you know! You think I don't know what you're up to?","TWN":"嘖，我也是海盜，你以為我不知道你們的算盤嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_SERIOUS"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"우릴 미끼로 써서 너희가 보물을 차지하려는 거잖아!","JPN":"俺たちをオトリにして、お前らが宝を独占しようとしてるんだろ！","ENG":"You're trying to use us as bait to have the treasure all to yourself!","TWN":"想拿我們當誘餌，好奪取寶藏！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"응, 맞아.","JPN":"ああ、そうさ。","ENG":"Yeah, that's right.","TWN":"嗯，沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하지만 다른 사람을 미끼로 이용할 수 있는 건, 당신들도 마찬가지잖아?","JPN":"でも他人をオトリとして利用するのは、あなたたちも一緒だろう？","ENG":"But you can also use someone else as bait too, no?","TWN":"但你同樣可以用別人做誘餌，不是嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"누군가는 보물을 얻고, 또 누군가는 심해에 묻히겠지만, 당신이 어느 쪽이 될지는 아무도 몰라.","JPN":"誰かは宝を手に入れ、誰かは深海に沈むだろうが、あなたがどちらになるかは誰もわからない。","ENG":"Some will get the treasure, and some will become fish food. But no one knows which one you'll end up as.","TWN":"有人會得到寶藏，有人會葬身海底，但你不清楚你會是哪一種。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"그렇다면… 배가 많을수록, 살아 돌아갈 가능성도 높아지겠군.","JPN":"だったら……船が多いほど、生きて帰る可能性も高くなるだろな。","ENG":"Then... the greater the number of ships, the greater our chances of survival.","TWN":"所以…船越多，生存的可能性就越大。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"너 미쳤어?! 저런 말도 안 되는 소리에 넘어가는 거야?!","JPN":"お前、本気か！？　あんなデタラメに騙されるのか！？","ENG":"Are you insane?! Don't tell me she's got you convinced!","TWN":"你有病？！你居然相信這種鬼話？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"쳇, 돌아가자.","JPN":"ちっ、戻るぜ。","ENG":"Tch, let's head back.","TWN":"嘖，我們回去吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_SERIOUS"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"…우리도 철수하자고.","JPN":"……俺たちも撤収しよう。","ENG":"...We should fall back as well.","TWN":"…我們也撤吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_IDLE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"가, 같이 가!","JPN":"い、一緒に行こう！","ENG":"W-wait for me!","TWN":"等…等等我！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_IDLE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"보물이라고…? 이런 게?","JPN":"宝……？　こんなものが？","ENG":"This is supposed to be treasure...? Really?","TWN":"這也算是…？寶藏？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…흐음, 심해에 묻혀 있던 물건들치곤 제법 멀쩡하네.","JPN":"……ふーん、深海に沈んでいた割には結構キレイだな。","ENG":"...Hmm, seems to be in good shape for something that's been buried deep in the ocean.","TWN":"嗯，對於埋在深海域的東西來說，算是很不錯吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"오, 세검도 있잖아?","JPN":"おお、レイピアもある。","ENG":"Ooh, there's even a rapier.","TWN":"喔，還有一把劍？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"갖고 싶나?","JPN":"欲しいか？","ENG":"Do you want it?","TWN":"想要嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"으앗, 깜짝아.","JPN":"うわっ、びっくりした。","ENG":"Whoa! Sheesh!","TWN":"哇啊，嚇我一跳。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"당신… 언제부터 거기 있던 거야?","JPN":"あなた……いつからそこにいたんだ？","ENG":"You're... How long have you been there?","TWN":"你…你什麼時候在那裡的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"방금 떠난 친구들이 내 배에 발을 디뎠을 때부터지.","JPN":"さっき立ち去った者たちが、私の船に足を踏み入れた時からだ。","ENG":"Since the fellas who left just now set foot on my ship.","TWN":"剛才離開的朋友們踏上我的船時，我就一直在這裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하? 자기 물건이 도둑맞는 걸 가만히 구경만 하고 있었다고?","JPN":"は？　自分の物が盗まれるのをただじっと見てたのか？","ENG":"Huh? So you were just watching them steal your stuff?","TWN":"蛤？你就這樣眼睜睜地看著自己的東西被偷嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 아가씨가 저 친구들의 존엄성을 지켜줬으니, 좋은 게 좋은 거 아니겠나?","JPN":"ハハハ！　お嬢さんがあの者たちの尊厳性を守ってあげたのだから、いいではないか。","ENG":"Gah hah hah! But you protected their dignity, lass. No harm, no foul, right?","TWN":"哈哈哈！你還替他們留面子，算是好事一樁吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"오해야. 남의 존엄성을 챙겨줄 만큼 인심 좋은 사람은 아니거든.","JPN":"誤解だ。他人の尊厳性を守ってあげるほどお人好しじゃないから。","ENG":"That's a misunderstanding. I'm not generous enough to care about someone else's dignity.","TWN":"這事誤會，我不是那種在乎別人尊嚴的人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 어째서 내 보물을 대신 지켜준 거지?","JPN":"だとしたら、どうして私の宝を代わりに守ってくれたんだ？","ENG":"Then, why did you guard my treasure for me?","TWN":"那你為什麼要替我看守我的寶藏？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"우린 바다의 보물이 갖고 싶으니까.","JPN":"あたしたちは海の宝が欲しいから。","ENG":"Because we want the ocean's treasure.","TWN":"因為我們想要大海的寶藏。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저 녀석들이 당신 보물을 훔쳐서 원하는 걸 얻게 되면, 절박함이 사라질 거 아냐?","JPN":"あいつらがあなたの宝を盗んで望むものを手に入れたら、切迫感がなくなるだろう？","ENG":"If they get what they want by stealing from you, their desperation will also disappear, don't you think?","TWN":"如果他們偷走你的寶藏，得到他們想要的，危機感就會消失不是嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"결국 목숨 걸고 당신을 따라나서지 않으면, 돈을 벌 다른 방법이 없다는 걸 알려줘야지.","JPN":"最終的に命をかけてあなたについて行かないと、お金を稼ぐ方法が他にないということを教えてあげないと。","ENG":"They need to learn that they can't earn any money unless they risk their lives and follow you to sea.","TWN":"必須讓他們知道，如果他們不冒著生命危險追隨你，就沒有其他賺錢的途徑。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그러다 저 녀석들이 프론트베이를 떠나 다른 일자리를 알아보게 되면 어쩌려고 그러나?","JPN":"だがあいつらがフロントベイを出て他の働き口を探すことになったらどうするんだ？","ENG":"What if they start looking into other jobs within Front Bay?","TWN":"但要是他們離開前灣，尋找其他出路呢，又該怎麼辦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"푸핫-","JPN":"ぶはっ！","ENG":"Haha-!","TWN":"噗哈。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그거 참 이성적인 판단이네.","JPN":"それはまあ、理性的な判断だな。","ENG":"That's a rather rational decision.","TWN":"那是一個非常明智的決定。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런데 프론트베이의 바다를 떠도는 인간치고, 이성만 가지고 살아가는 인간은 없을걸?","JPN":"でもフロントベイの海を流離う者なら、理性だけで生きている人はいないはずだ。","ENG":"But I don't think there's anyone in Front Bay who roams the ocean and only makes rational decisions.","TWN":"不過，對於徘徊在前灣海域的人來說，理性是不存在的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그럴지도 모르겠군.","JPN":"そうかもしれないな。","ENG":"I suppose so.","TWN":"也許吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이 바다에선… 이성을 압도하는 욕망이 없으면 살아남기 힘드니까.","JPN":"この海では……理性を圧倒する欲望がないと生き残るのは大変だから。","ENG":"The sea... It's hard to survive if one doesn't have a desire that triumphs over rationality.","TWN":"在這片汪洋大海中…如果沒有壓倒理智的欲望，就很難生存。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 하나 묻고 싶은데.","JPN":"それならば、一つ聞きたいのだが。","ENG":"Let me ask you another question.","TWN":"如果是這樣，我有一個問題。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"나한테? 뭔데?","JPN":"あたしに？　なんだ？","ENG":"To me? What is it?","TWN":"嗯？你想問我什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨를 지금 해적으로 있게 해주는 욕망은 뭐지?","JPN":"お嬢さんを海賊でいさせる欲望とは何だ？","ENG":"What drives your desire to be a pirate, lass?","TWN":"是什麼欲望讓你選擇當海盜？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"말했잖아. 생선이라고.","JPN":"言っただろう。魚だ。","ENG":"I already told you, it's fish.","TWN":"我告訴過你，因為魚。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫, 그땐 농담인 줄 알았는데. 진심으로 하는 소리였나?","JPN":"ハハハ、あの時は冗談だと思ったが。本気だったのか？","ENG":"Gah hah hah! I thought that was a joke. You were telling the truth?","TWN":"哈哈哈，我當時還以為你在開玩笑，你是認真的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"내가 지내던 고아원에선 매일 생선을 먹었어.","JPN":"あたしが暮らしていた孤児院では毎日魚を食べていた。","ENG":"In the orphanage I grew up in, we had fish every day.","TWN":"我待過的孤兒院每天都有魚吃。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아이들은 매일 생선만 먹는다고 질색을 했지만, 난 좋아했거든.","JPN":"子どもたちは毎日魚だってうんざりしていたけど、あたしは好きだった。","ENG":"The other kids hated that it was the only thing we ate, but I liked it.","TWN":"雖然其他孩子不喜歡每天吃魚，但我很喜歡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"고아원을 떠나고 나서야 알게 된 사실은…","JPN":"孤児院を出て知った事実は……","ENG":"And one thing I found out after leaving the orphanage was...","TWN":"直到離開孤兒院我才意識到…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 생선이 내항의 양식장 어디에서도 구할 수 없는 생선이었단 거야.","JPN":"あの魚が、内港のどの養殖場からも手に入らない魚だってことだった。","ENG":"that the fish I ate was impossible to find on fish farms in the harbor.","TWN":"內港的任何養殖場都沒有這種魚。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"문득 궁금해지더라고.","JPN":"ふと気になったんだ。","ENG":"So I got curious.","TWN":"我突然有些好奇。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"원장님이 말하던 그 은사라는 사람은 대체 이 귀한 생선들을 어디에서 구했던 걸까?","JPN":"院長が言ってたあの恩師って人は、いったいどこでこんな珍しい魚を手に入れたのか。","ENG":"Who is this teacher the dean referred to, and how did this person source all these rare fish?","TWN":"院長所說的那個人，究竟是從哪裡得到這些珍貴海鮮的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그렇게 난, 과거의 흔적을 쫓는 사냥꾼이라도 된 것처럼 온 바다를 유랑했어.","JPN":"そうやってあたしは、過去の痕跡を追うハンターのように全の海を流浪した。","ENG":"And so, I started wandering the ocean like a hunter, chasing after traces of the past.","TWN":"就這樣，我在海上流浪，像獵人一樣追尋著過去的痕跡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 생선이 다시 먹고 싶어서.","JPN":"あの魚がまた食べたくて。","ENG":"To eat that fish again.","TWN":"我想再吃一次那種魚。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런 간단하고, 시시한 이유야.","JPN":"そんな単純で、つまらない理由だ。","ENG":"It's a simple yet stupid reason.","TWN":"就是這麼簡單、無聊的原因。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래서, 원하던 생선은 찾았나?","JPN":"それで、求めていた魚は見つけたのか？","ENG":"So, have you found that fish yet?","TWN":"那你有找到你要找的魚嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"쉽진 않더라고.","JPN":"簡単ではなかった。","ENG":"It's not that easy.","TWN":"這並不容易。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그때 그 생선의 맛도 이젠 가물가물해서, 지금은 반쯤 포기했어.","JPN":"あの時のあの魚の味もすでにぼんやりしてきて、今は半分諦めてる。","ENG":"Its taste is beginning to fade into memory, so I kinda gave up.","TWN":"我已經快要忘記那種魚的味道了，目前呈現半放棄狀態。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래도 후회하진 않아. 지금은 생선이 아니라도, 내가 살아갈 또다른 이유가 생겼으니까.","JPN":"それでも後悔はしない。今は魚じゃなくても、あたしが生きるもう一つの理由ができたから。","ENG":"But I don't regret it. Now, I have other reasons to live besides the fish.","TWN":"但我並不後悔，因為現在我又多了一個活下去的理由。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그 눈빛… 샤크스의 멤버들을 말하는 거군.","JPN":"その目……シャークスのメンバーのことだな。","ENG":"Those eyes... You're talking about the Shark members.","TWN":"這個眼神…你的理由就是大白鯊的夥伴吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런 것 같아.","JPN":"そうだと思う。","ENG":"I think so.","TWN":"應該是。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"늘 목숨으로 곡예를 벌이는 선장과 말괄량이 폭탄마 때문에 하루도 조용한 날이 없지만.","JPN":"いつも命をかけて綱渡りする船長と、おてんばな爆弾魔のせいで一日も穏やかに過ごせないけど。","ENG":"Although never a day goes by in peace with the captain, who pulls stunts with her life on the line, and with the crazy blastomaniac.","TWN":"雖然船長和炸彈客總是以身試險，沒有一天平靜的日子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 덕분에, 매일 살아있다는 걸 느껴.","JPN":"あいつらのおかげで、毎日生きてるって実感する。","ENG":"But because of them, I feel alive every day.","TWN":"但也多虧有他們，我每天都覺得自己還活著。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"……아.","JPN":"……あ。","ENG":"...Oh.","TWN":"……啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"방금 한 말은 그냥 잊어. 좀 오글거리네.","JPN":"今の言葉は忘れろ。ちょっと鳥肌立ってきた。","ENG":"Forget what I just said. Just saying it made me cringe.","TWN":"忘掉我剛才說的話，怪肉麻的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 오글거릴 게 뭐가 있나? 해적스럽고 낭만적이기만 한데!","JPN":"ハハハ！　鳥肌が立つことはないだろう？　海賊らしくてロマンチックではないか！","ENG":"Gah hah hah. What's there to cringe? Sounds like you're living the pirate dream.","TWN":"哈哈哈！肉麻有一點有什麼不好？這很符合海盜式的浪漫！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"좋은 일이라고. 믿고 등을 맡길 수 있는 동료와 함께 한다는 건 말이야.","JPN":"いいことだ。信じて背中を預けられる仲間とともにいるというのは。","ENG":"It's a good thing. To have a crew you can count on.","TWN":"這是件好事，有值得信賴的同伴是件好事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yeah.","TWN":"嗯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};